package com.enterprise.secureapp.service;

import com.enterprise.secureapp.dto.CreateTransactionRequest;
import com.enterprise.secureapp.dto.TransactionDTO;
import com.enterprise.secureapp.entity.Transaction;
import com.enterprise.secureapp.entity.User;
import com.enterprise.secureapp.repository.TransactionRepository;
import com.enterprise.secureapp.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;

@Service
@Transactional
public class TransactionService {
    
    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;
    private static final Set<String> ALLOWED_TRANSACTION_TYPES = Set.of("DEPOSIT", "WITHDRAWAL", "TRANSFER", "PAYMENT");
    private static final Set<String> ALLOWED_CURRENCIES = Set.of("USD", "EUR", "GBP");
    
    @Autowired
    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }
    
    public TransactionDTO createTransaction(Long userId, CreateTransactionRequest request) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new IllegalArgumentException("User not found"));
        
        if (!user.getActive()) {
            throw new IllegalArgumentException("User account is not active");
        }
        
        if (!ALLOWED_TRANSACTION_TYPES.contains(request.getType())) {
            throw new IllegalArgumentException("Invalid transaction type");
        }
        
        if (!ALLOWED_CURRENCIES.contains(request.getCurrency())) {
            throw new IllegalArgumentException("Invalid currency");
        }
        
        Transaction transaction = new Transaction();
        transaction.setUser(user);
        transaction.setAmount(request.getAmount());
        transaction.setCurrency(request.getCurrency());
        transaction.setType(request.getType());
        transaction.setStatus("PENDING");
        transaction.setDescription(request.getDescription());
        transaction.setReferenceNumber(generateReferenceNumber());
        
        Transaction savedTransaction = transactionRepository.save(transaction);
        return convertToDTO(savedTransaction);
    }
    
    @Transactional(readOnly = true)
    public TransactionDTO getTransactionById(Long id) {
        Transaction transaction = transactionRepository.findById(id)
            .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        return convertToDTO(transaction);
    }
    
    @Transactional(readOnly = true)
    public Page<TransactionDTO> getTransactionsByUserId(Long userId, Pageable pageable) {
        if (!userRepository.existsById(userId)) {
            throw new IllegalArgumentException("User not found");
        }
        
        return transactionRepository.findByUserId(userId, pageable)
            .map(this::convertToDTO);
    }
    
    @Transactional(readOnly = true)
    public List<TransactionDTO> getTransactionsByUserIdAndStatus(Long userId, String status) {
        if (!userRepository.existsById(userId)) {
            throw new IllegalArgumentException("User not found");
        }
        
        return transactionRepository.findByUserIdAndStatus(userId, status).stream()
            .map(this::convertToDTO)
            .collect(Collectors.toList());
    }
    
    public TransactionDTO updateTransactionStatus(Long id, String status) {
        Transaction transaction = transactionRepository.findById(id)
            .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        
        Set<String> allowedStatuses = Set.of("PENDING", "COMPLETED", "FAILED", "CANCELLED");
        if (!allowedStatuses.contains(status)) {
            throw new IllegalArgumentException("Invalid status");
        }
        
        transaction.setStatus(status);
        
        if ("COMPLETED".equals(status)) {
            transaction.setCompletedDate(LocalDateTime.now());
        }
        
        Transaction updatedTransaction = transactionRepository.save(transaction);
        return convertToDTO(updatedTransaction);
    }
    
    @Transactional(readOnly = true)
    public TransactionDTO getTransactionByReferenceNumber(String referenceNumber) {
        Transaction transaction = transactionRepository.findByReferenceNumber(referenceNumber)
            .orElseThrow(() -> new IllegalArgumentException("Transaction not found"));
        return convertToDTO(transaction);
    }
    
    private String generateReferenceNumber() {
        return "TXN-" + UUID.randomUUID().toString().toUpperCase();
    }
    
    private TransactionDTO convertToDTO(Transaction transaction) {
        TransactionDTO dto = new TransactionDTO();
        dto.setId(transaction.getId());
        dto.setUserId(transaction.getUser().getId());
        dto.setAmount(transaction.getAmount());
        dto.setCurrency(transaction.getCurrency());
        dto.setType(transaction.getType());
        dto.setStatus(transaction.getStatus());
        dto.setDescription(transaction.getDescription());
        dto.setReferenceNumber(transaction.getReferenceNumber());
        dto.setTransactionDate(transaction.getTransactionDate());
        dto.setCompletedDate(transaction.getCompletedDate());
        return dto;
    }
}

